# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import json
from http.server import BaseHTTPRequestHandler, HTTPServer
import pymysql

class SearchAPI(BaseHTTPRequestHandler):
    def do_GET(self):
        params = self.parse_qs(self.path.split('?')[1])
        query_parts = ['SELECT * FROM your_table']
        
        if 'field' in params and 'value' in params:
            field = params['field'][0]
            value = params['value'][0]
            query_parts.append(f"WHERE {field} = '{value}'")
        
        query = ' '.join(query_parts)
        
        try:
            conn = pymysql.connect(host='your_host', user='your_user', password='your_password', db='your_db')
            with conn.cursor() as cursor:
                cursor.execute(query)
                results = cursor.fetchall()
            
            self.send_response(200)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps(results).encode())
        except Exception as e:
            self.send_response(500)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps({'error': str(e)}).encode())

def run(server_class=HTTPServer, handler_class=SearchAPI, port=8080):
    server_address = ('', port)
    httpd = server_class(server_address, handler_class)
    print(f'Starting httpd on port {port}')
    httpd.serve_forever()

if __name__ == '__main__':
    run()